var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다이브 작전이라...... 예전 생각 나네.","JPN":"ダイブ作戦か……少し前のことを思い出すな。","ENG":"A Dive operation, huh... It reminds me of back in the day...","TWN":"躍入作戰……想起以前的事了呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 때는 정말 난리도 아니었지.","JPN":"あの時は本当に散々だった。","ENG":"Things got really hectic back then.","TWN":"當時真是一團糟。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알트 소대는 멋대로 사라지지 않나, 그림자라는 게 튀어나오지 않나......","JPN":"アルト小隊は勝手に消えるし、シャドウとかいうのがいきなり出てきて……","ENG":"The ALT Squad went AWOL, and those Shadow things popped out of nowhere...","TWN":"阿爾特小隊自作主張消失了，還出現了暗影……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 때에 비하면 이번 다이브는 정말 평화......","JPN":"あの時に比べれば今回のダイブは本当に平和……","ENG":"Compared to that, this Dive is pretty peaceful—","TWN":"比起那時，這次的躍入真是平靜……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자기가 먼저 도망치면 어떡해요, 선배?! 후배를 지켜 줘야죠!","JPN":"先に逃げてどうするんですか、先輩！？　後輩を守るべきでしょう！？","ENG":"You can't run away, Ray! You should protect your underclassmen!","TWN":"你怎麼能自己先跑呢，前輩？！你要保護後輩啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그치만 나도 침식체한테 공격 받으면 아픈걸......","JPN":"だ、だって僕も侵食体に攻撃されたら痛いんだよ……","ENG":"B-but those C.O.s could hurt me too...","TWN":"但，我如果被侵蝕體攻擊也會疼的啊……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어휴! 듬직한 구석이 없어, 진짜!","JPN":"もお！　頼もしいところが1ミリもないんだから！","ENG":"Gosh! You're totally unreliable!","TWN":"哎～真是的！一點也靠不住！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"꺄아악! 미나야! 살려 줘!","JPN":"きゃーっ！　ミナちゃーん！　助けて！","ENG":"Eeek! Mina! Help me!","TWN":"啊啊啊! 米娜！救救我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......롭진 않네.","JPN":"……平和ではないな。","ENG":"I'm taking my words back.","TWN":"……也平靜不了了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만 기다려! 지금 갈게!","JPN":"待って！　今行くから！","ENG":"Hang on! I'll be right there!","TWN":"等一下！馬上就過去！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"혹시라도 적응 못 하면 어쩌나 했는데, 괜한 걱정이었던 것 같군.","JPN":"もし馴染めなかったらどうしようかと思ったが、余計な心配だったようだな。","ENG":"I guess my concerns about you having trouble acclimating were completely unfounded.","TWN":"本來還擔心你不能適應，現在看起來真是白操心了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알렌 선생님? 선생님도 훈련에 따라온 거야?","JPN":"アレン先生？　先生も訓練についてきたの？","ENG":"Prof? You tagged along on this Dive?","TWN":"艾倫老師？老師也來參加訓練嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이번 훈련은 내가 직접 기획한 프로젝트라네. 당연히 동행해야지.","JPN":"今回の訓練は私が企画したプロジェクトだ。同行するのは当たり前だ。","ENG":"This very training program is my brainchild. Of course I'm here.","TWN":"這次的訓練計畫是我負責的，我當然要陪同了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고...... 신경이 쓰이는 구석도 있어서.","JPN":"そして……気になることもあってな。","ENG":"Besides... I couldn't help but notice something...","TWN":"還有……有些需要我操心的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신경이 쓰이다니, 뭐가?","JPN":"気になるって？　何が？","ENG":"Notice what?","TWN":"要操心的事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"서류를 봤는데 레이가 이번 훈련에 자네 팀으로 참가를 신청했더군.","JPN":"書類を確認したが、レイは今回の訓練で君と同じチームとして参加したようだな。","ENG":"I read in the files that Ray volunteered to participate in this Dive on your team.","TWN":"我看了資料，這次訓練中雷伊跟你是一隊的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"솔직히 말해서 놀랐다. 그 녀석이 이런 훈련에 참가하겠다고 나설 줄은 생각 못했거든.","JPN":"正直驚いた。あの子がこの類の訓練に参加するとは思っていなかったから。","ENG":"Honestly, I was rather surprised. I never expected him to participate in a training mission like this.","TWN":"說實話我很吃驚。那傢伙竟然會參加訓練，真是太意外了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 미카가 조금 억지로 데려오긴 했어.","JPN":"まあ、ミカが無理やり連れてきた感はあるけどね。","ENG":"Well, Mika sort of dragged him into it against his will.","TWN":"那個，是被米卡硬拉過來的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이미 얘기를 들었는지 모르겠지만, 나와 레이는 개인적으로 조금 친분이 있는 사이라네.","JPN":"すでに話を聞いているかもしれないが、私とレイは個人的な繋がりがある。","ENG":"I don't know if you've heard, but I have a somewhat personal relationship with Ray.","TWN":"我不知道你聽說過沒有，我和雷伊是親戚關係。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미카에게 들었어. 먼 친척이라던데.","JPN":"ミカから聞いているよ。遠い親戚なんだってね。","ENG":"Mika told me. She said you're distant cousins?","TWN":"我聽米卡說過了，說你們是遠親。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그래. 교사로서 특정 학생을 편애해선 안 되지만, 관심이 가는 건 어쩔 수 없더군.","JPN":"そうだ。教師として特定の生徒を特別扱いするのはよくないが、やはり気になるのも仕方がなくてな。","ENG":"Yeah. I know I shouldn't play any favorites as a faculty member, but I couldn't help pay extra attention to the boy.","TWN":"是啊。作為老師雖然不能偏愛特定一個學生，但總是會不自覺地多關注他。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"레이는 아주 뛰어난 잠재력을 가지고 있는 학생이야.","JPN":"レイはとても優れた潜在能力の持ち主だ。","ENG":"Ray has a lot of potential.","TWN":"雷伊是非常有潛力的學生。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 저 성격 탓에 그동안 어디에도 정을 못 붙이고 겉돌기만 해 왔지.","JPN":"だが、彼の性格のせいで今までどこにも属することができず、空回りしてしまった。","ENG":"Being as introverted as he is, he just never managed to find the right companions.","TWN":"但因為自身性格原因一直沒辦法融入群體，一個人獨來獨往。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전투 훈련에서 매번 변변치 못한 모습만 보이는 것도 그런 정신적인 문제 때문이야.","JPN":"戦闘訓練で毎回活躍できないのも、その精神的な問題のせいだ。","ENG":"Even his poor performance in combat training is due to his frail state of mind.","TWN":"在戰鬥訓練中每次都發揮失常，也是因為心裡上的問題。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고쳐 보려고 아무리 애를 써도 금방 원래의 나약한 태도로 돌아가 버렸지.","JPN":"治そうといくら頑張ってみても、すぐ元の軟弱な態度に戻ってしまってね。","ENG":"No matter how hard he tries, he always ends up retreating back to his old shy self again.","TWN":"雖然他也努力改正，但沒多久又會變回原本的懦弱性格。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 자네는 편입한 지 며칠 되지도 않아서 레이를 여기까지 데리고 왔어. 아주 대단해.","JPN":"しかし君は編入から数日しか経っていないが、レイをここまで連れてきた。実に見事だ。","ENG":"But you managed to bring Ray here, only days after transferring to the Academy. That's remarkable.","TWN":"你入學沒幾天就能將雷伊帶到這裡來。真是不簡單。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 그냥 조금 내성적인 사람이라고만 생각했는데......?","JPN":"そう？　少し内気な人だと思ってはいたけど……","ENG":"Is that right? I just thought he was a bit shy...","TWN":"是嗎？我以為他只是性格比較內向……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네는 억지라고 말했지만 레이가 그렇게라도 훈련에 참가한 건 이번이 처음이야.","JPN":"さっき無理やりとは言ったが、それでもレイが訓練に参加したこと自体が今回初めてなのさ。","ENG":"You may say he was dragged into this, but this is the first time he participated at all in tactical training.","TWN":"雖然你說是米卡硬拉過來的，但哪怕用這種方式，這也是雷伊第一次參加訓練。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어쩌면 자네가...... 레이의 닫힌 마음을 열 계기가 될지도 모르겠군.","JPN":"もしかしたら君が……レイの閉ざされた心を開くきっかけになるかもしれない。","ENG":"Perhaps... You may be the key to opening his heart.","TWN":"或許你……就是雷伊敞開心扉的契機。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"닫힌 마음을 연다고?","JPN":"閉ざされた心を開く？","ENG":"Opening his heart?","TWN":"敞開心扉？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"누구나 자기만의 세계에서 영원히 살 수는 없는 법이야.","JPN":"人間誰しも、自分だけの世界で永遠を生きることはできない。","ENG":"No one can live forever in their own little world.","TWN":"沒有人能永遠活在只有自己的世界裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"스스로 원하지 않아도 언젠가 세상 밖으로 나가야 할 때가 오는 법이지.","JPN":"本人が望んでいなくても、いつかは外の世界に出るべき時がくる。","ENG":"One day, he'll have to break out of that shell into the real world, whether he wants to or not.","TWN":"就算自己不願意，總有一天也會從自己的世界中走出來。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"글쎄, 내 생각엔 그렇게 걱정 안 해도 될 것 같아.","JPN":"そうだね、個人的にはあまり心配することではないと思うよ。","ENG":"Well, I don't think you have to worry that much about him.","TWN":"反正，我是覺得沒必要過分擔心。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"레이 선배가 내성적이긴 해도 책임감이 없는 사람은 아니거든.","JPN":"レイ先輩は内気ではあるけど、責任感がないわけではないんだ。","ENG":"He may be a bit introverted, but he's not completely irresponsible.","TWN":"雷伊前輩雖然有些內向，但不是沒有責任感的人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시뮬레이터가 오작동을 일으킬 때도 끝까지 자리를 지켜 줬고, 오늘도 훈련에 나왔잖아.","JPN":"シミュレーターが誤作動した時も最後まで残ってくれたし、今日も訓練に来てくれた。","ENG":"When the simulator malfunctioned, he stuck around till the end. He even came out to train today.","TWN":"在模擬器故障的時候，也一直堅守自己的位置。今天也參加了訓練。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그때나 지금이나 도망칠 생각이었으면 어떻게든 도망칠 수 있었을걸?","JPN":"あの時も今も逃げる気があったなら、何かしら言い訳をして逃げたはずだよ？","ENG":"He could have bailed at any moment if he wanted to.","TWN":"不管是當時還是現在，如果他想要逃跑的話，總是有辦法的吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 보기엔 선배는 믿을 만한 사람이야.","JPN":"先輩は信用できるタイプだと思う。","ENG":"I, for one, think Ray is a reliable person.","TWN":"在我看來，前輩是可以信賴的人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니 선생님도 믿고 지켜봐 주면 좋겠어.","JPN":"だから先生も信じて見守ってほしい。","ENG":"So I hope you'll have a little more faith in him as well.","TWN":"所以希望老師也能相信他。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......그건 경험담인가?","JPN":"……それは経験話か？","ENG":"Are you speaking from experience?","TWN":"……你好像是有感而發？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아...... 하하, 눈치챘어?","JPN":"あ……ハハハ……バレた？","ENG":"Oh... Hah hah, did you notice?","TWN":"啊……哈哈，被你看出來了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실은 솔직하지 못한 것 하나는 선배랑 판박이인 친구가 있었거든.","JPN":"素直じゃないところが先輩と全く同じ友達がいたんだ。","ENG":"I had a friend who was terrible at being honest with herself, just like Ray.","TWN":"其實我也有個朋友與前輩一樣，不夠坦誠。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석도...... 결국 자기 마음에 솔직해지기로 했으니까.","JPN":"あいつも……結局自分の気持ちに素直になることにしたから。","ENG":"But even she... finally decided to be honest about her own feelings.","TWN":"那傢伙……最後也決心誠實面對自己的內心。"},"stage":{"bg":"MAINSTREAM_5508010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선생님이 믿어 주면 레이 선배도 옳은 선택을 할 수 있을 거야.","JPN":"先生が信じてあげれば、レイ先輩も正しい選択ができると思う。","ENG":"With your support, I'm sure Ray will make the right decision one day too.","TWN":"如果老師能夠信任雷伊前輩，他會做出正確的選擇的。"},"stage":{"bg":"MAINSTREAM_5508010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5508010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"모두가 아무도 믿지 말라고 떠드는 시대인데, 자네는 한 번 더 믿어 보라고 하는군.","JPN":"皆が誰も信じるなと騒ぐこの時代に、君はもう一度信じろと言うんだな。","ENG":"Everyone says trust is overrated in this day and age... yet you insist that I give it another try.","TWN":"在所有人都失去信任的時代，你卻說要相信。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하긴, 그럴 수 있어야 동료이자...... 친구인 거겠지.","JPN":"まあ、そう言えるのが仲間であり……友達なんだろうな。","ENG":"I guess that's what true companions... and true friends are for.","TWN":"也是，只有信任才能成為同伴……才是朋友吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아무래도 만난 지 얼마 안 된 자네가 나보다 레이를 더 잘 이해하는 것 같군.","JPN":"どうやら出会ったばかりの君のほうが私よりもレイのことを理解しているようだ。","ENG":"Looks like you understand Ray better than I do, even though you just met him.","TWN":"雖然你們認識不久，但我覺得你比我更瞭解雷伊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이번 훈련 동안, 나 대신 레이를 잘 부탁하네.","JPN":"今回の訓練の間は私の代わりにレイのことをよろしく頼む。","ENG":"Please take good care of Ray on my behalf throughout this training.","TWN":"這次訓練，就拜託你照顧雷伊了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알겠어. 큰 도움이 될지는 모르겠지만.","JPN":"いいよ。そんなに役に立てるかはわからないけどね。","ENG":"Will do. Although I'm not sure how helpful I'll really be.","TWN":"好的，雖然不知道我能幫到他什麼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};